import{_ as e,o as t,c as a,Q as p}from"./chunks/framework.1eb6b028.js";const f=JSON.parse('{"title":"社会性动物","description":"摘抄","frontmatter":{"title":"社会性动物","description":"摘抄","date":"2023-05-03T00:00:00.000Z","tags":["笔记"]},"headers":[],"relativePath":"posts/非技术类/社会性动物.md","filePath":"posts/非技术类/社会性动物.md"}'),o={name:"posts/非技术类/社会性动物.md"},s=p('<h2 id="什么是社会心理学" tabindex="-1">什么是社会心理学 <a class="header-anchor" href="#什么是社会心理学" aria-label="Permalink to &quot;什么是社会心理学&quot;">​</a></h2><p>社会心理学定义：他人真实的、想象的或暗示的存在，对我们的思想、情感、信仰和行为的影响，以及我们如何影响他人的科学研究。</p><p>影响策略：年龄、人格动力、社会认同、说服策略以及其他强有力的因素。</p><p>事后聪明偏见：知道某一件事的结果，就会高估自己的预测能力。</p><p>认知偏差的案例：面对轻微惩罚时，人们会讨厌被禁止的行为，而受到严重威胁的人，更可能受到被禁止的活动的吸引。 我们无意中听到背后有人说我们好，会喜欢这个人，加入无意中听到的不完全是好话，我们会更加喜欢这个人。</p><p>阿伦森第一定律：做出疯狂举动的人未必疯狂。</p><p>琼斯城大屠杀：1977旧金山人民圣殿教教主Jim Jones说服追随者们（613个家庭）搬迁到南美洲的圭亚那，建立人可以和谐生活的乌托邦社区。1978年收到国会调查的威胁时，Jim Jones要求组织成员杀死自己孩子，然后自杀。 提醒我们：社会影响会决定人们的想法、感受和行为。这种影响往往巨大而隐秘。</p><h2 id="社会认知" tabindex="-1">社会认知 <a class="header-anchor" href="#社会认知" aria-label="Permalink to &quot;社会认知&quot;">​</a></h2><p>案例：中世纪欧洲，市民会将尿液和粪便从窗户倒上街，而早起文明--希腊、罗马和玛雅人已经拥有了较好的排污系统，夜壶取代室内管道的原因竟然是：当时人们认为赤身裸体是罪孽深重的，当一个人赤身裸体时会遭受恶魔攻击。</p><p>案例：在维多利亚时代，那些医生提到人们害怕洗澡和鬼魂便加以嘲笑，但他们仍然相信自己那个时代的荒谬之伦：女性阅读小说会存在引发疾病、不育甚至精神错乱。</p><p>社会认知：是社会心理学的主要研究领域，关注：人们如何相信自己所做的事，人们如何解释、记忆、预测、决策、评价自己和他人，以及这些过程为什么经常产生错误。</p><p>在很多时候，我们采用理性、事实和批判性分析，不是为了形成我们的观点，而是为了确证我们已经看到、感觉到或者相信的东西。</p><p>我们看到的并非事实的本来面目，而是我们所看到的事物的本来面目。 by Anais Nin</p>',13),_=[s];function r(n,i,c,d,l,h){return t(),a("div",null,_)}const u=e(o,[["render",r]]);export{f as __pageData,u as default};
